  "verses": [
    {
      "n": 41,
      "column": "left",
      "text": "tſchetrpadeſmits Gaddus eſinu es\ntew par tawahm diwi Meitahm\nkalpojis / un feſch Gaddus par\ntawahm Awini/ un tu effiman-\nnu Algu deſmitkahrt pahrgroh-\nfijis."
    },
    {
      "n": 42,
      "column": "left",
      "text": "Kaut manna Tehwa\nDeews / tas Ahbrâaima Deews/\nun Ihsâika Bihjaschana ne\nbuhtu pee man bijis/ tu nu buh-\ntu mann tukchu aissuhtijis /\nDeews irr mannas Behdas/ un\nmanno Rohku Darbu usluhko-\njis / un tew tsgahjuſchâ Nakti\nupsauzis."
    },
    {
      "n": 43,
      "column": "left",
      "text": "Tad athildeja Lahbans\nun fazzija uhs Jehkabu : Tahs\nMeitas irr mannas Meitas/ un\ntee Behrni irr manni Behrni /\nuntahs Awis irr mannas Awis/\nun wifs/ ko tu redſi / tas irr\nmans/ un ko darrifchu es schahm\nmannahm Meitahm fchodeen/jeb\nwinno Behrneem / ko tahs irr\ndsemdejuſchas."
    },
    {
      "n": 44,
      "column": "left",
      "text": "Un nu nahz / darrifſin\nDerribu / es un tu / ka ta effoti\npar Leezibu ſtarp man/ un ſtarp\ntew."
    },
    {
      "n": 45,
      "column": "left",
      "text": "Un Jehkabs nehme wee-\nnu Akmini / un uszehle to par\nSihmi."
    },
    {
      "n": 46,
      "column": "left",
      "text": "Un Jehkabs fazzija us fa-\nweem Brahteem : Salaſſait Ak-\nminus/ un tee nehine Akminius/\nun falikfe tohs weena Kohpâ/ un\nehde tur wirs to Kohpu."
    },
    {
      "n": 47,
      "column": "left",
      "text": "Un Lahbans noſauze to\nJegar-Sâaduta/bet Jehkabs no-\nsauze to Gilead,"
    },
    {
      "n": 47,
      "column": "right",
      "text": "Un Lahbans fazzija : Sch\nKohpa laid fchodeen Leezibu dohd\nſtarp man/ un ſtarp tew/ tapeh-\ntappe winna Wahrdg nosaukt\nGilead."
    },
    {
      "n": 48,
      "column": "right",
      "text": "Un Mizpa / tapehz / k\nwiſch fazzija : Lai tas KUNGE\nredſ us man / un us tew / ka\nmehs weens ohtru ne redſe-\nmees."
    },
    {
      "n": 50,
      "column": "right",
      "text": "Ja tu apbehdinaſi man-\nnas Meitas / un nemſees See-\nwas pahr mannahm Meitahm\nNe weens irr pee muins / redſi\nDeews buhs Leezineeks star-\nman/ un ſtarp tewis."
    },
    {
      "n": 51,
      "column": "right",
      "text": "Tad fazzija Lahbans uh-\nJehkabu : Redſ/ tchi Kohpa / u-\nredſ / tchi uszelta Sihme / ko e-\nuszehlis efmu ſtarp man / u-\nſtarp tew."
    },
    {
      "n": 52,
      "column": "right",
      "text": "Schi Kohpa laid Leezib-\ndohd/ un tchi uszelta Sihme la-\nLeezibu dohd/ ka es ne eefchu pat-\nri pee tew / fezzen fcho Kohpu-\nun ka tew ne buhs pahri nahkt-\nfezzen fcho Kohpu/ un fcho usze-\ntu Sihmi/ taunu darriht."
    },
    {
      "n": 53,
      "column": "right",
      "text": "Ahbrâaima Deews/ u-\nNaöra Deews/ un winno Te-\nwu Deews/lai teefa ſtarp muins"
    },
    {
      "n": 54,
      "column": "right",
      "text": "Un Jehkabs svebreja pe-\nfawa Tehwa Ihsâika Bihjascha-\nnas/ un Jehkabs uppureja Up-\npuri Kalnâ/ un aizinaja fawu-\nBrahkus Maisti ehſt/ un tee eh-\nMaisti/ un palikfe par Nakti u-\nto Kalnu."
    },
    {
      "n": 55,
      "column": "right",
      "text": "Un Lahbans zehlahs Riht-\nagri/ un fkuhpſtija fawus Beh-\nnu"
    }
  ],
  "confidence": "high",
  "notes": ""
}
